// frontend/src/components/shared/Icons.jsx
//
// Custom filled icons. Each one is drawn on an 800x800 grid (viewBox) and
// FILLED rather than stroked, so the wrapper sets fill="currentColor" —
// meaning every icon takes on the surrounding text color automatically.
// fillRule="evenodd" is what carves the hole in the gear's center and the
// cut-out dabs in the palette; the sword overrides it to "nonzero" so its
// overlapping blades fill solid instead of cancelling out.
import React from 'react';

function Icon({ size = 20, children, ...props }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      viewBox="0 0 800 800"
      fill="currentColor"
      fillRule="evenodd"
      clipRule="evenodd"
      aria-hidden="true"
      {...props}
    >
      {children}
    </svg>
  );
}

