// Shared — "share nodes" glyph: two link lines drawn first, three nodes
// painted over their ends. Separate <circle> elements (not one path) so the
// evenodd rule can't carve holes where a node overlaps a connector.
export function ShareIcon(props) {
  return (
    <Icon {...props}>
      <path d="M250,400 L560,210 M250,400 L560,590" fill="none" stroke="currentColor" strokeWidth="58" strokeLinecap="round" />
      <circle cx="250" cy="400" r="108" />
      <circle cx="560" cy="210" r="108" />
      <circle cx="560" cy="590" r="108" />
    </Icon>
  );
}

// Status: Deceased
